// Nodes with only prop fields — may have untyped children in children array.
const PROPS_ONLY = new Set(['CompilationUnit','Identifier','PrivateIdentifier','StringLiteral','NumericLiteral','BigIntLiteral','RegularExpressionLiteral','NoSubstitutionTemplateLiteral','TemplateHead','TemplateMiddle','TemplateTail','JsxText']);

/** JSON-safe representation of a KS node. */
export interface JSONNode {
  kind: string;
  pos: number;
  end: number;
  text?: string;
  children?: JSONNode[];
  leadingComments?: KSCommentRange[];
  trailingComments?: KSCommentRange[];
  [key: string]: unknown;
}

/** Serialize a single KSNode to a JSON-safe plain object. */
export function nodeToJSON(node: KSNode): JSONNode {
  const result: JSONNode = { kind: node.kind, pos: node.pos, end: node.end };
  if (node.text) result.text = node.text;
  if (node.leadingComments) result.leadingComments = node.leadingComments;
  if (node.trailingComments) result.trailingComments = node.trailingComments;
  const fields = F[node.kind];
  if (fields) {
    const n = node as any;
    for (const [name, tag] of fields) {
      const val = n[name];
      switch (tag) {
        case 'c': result[name] = nodeToJSON(val); break;
        case 'o': if (val != null) result[name] = nodeToJSON(val); break;
        case 'l': if (val && val.length > 0) result[name] = val.map(nodeToJSON); break;
        case 'p': if (val !== undefined && val !== '' && val !== false) result[name] = val; break;
      }
    }
  }
  // For nodes with only prop fields (e.g. CompilationUnit), serialize children array
  if (PROPS_ONLY.has(node.kind) && node.children.length > 0) {
    result.children = node.children.map(nodeToJSON);
  }
  return result;
}

/** Deserialize a JSON object back to a KSNode with typed fields + children. */
export function nodeFromJSON(data: JSONNode): KSNode {
  const children: KSNode[] = [];
  const node: any = {
    kind: data.kind,
    pos: data.pos ?? 0,
    end: data.end ?? 0,
    text: data.text ?? '',
  };
  if (data.leadingComments) node.leadingComments = data.leadingComments;
  if (data.trailingComments) node.trailingComments = data.trailingComments;
  const fields = F[data.kind];
  if (fields) {
    for (const [name, tag] of fields) {
      switch (tag) {
        case 'c': {
          const child = nodeFromJSON(data[name] as JSONNode);
          node[name] = child;
          children.push(child);
          break;
        }
        case 'o': {
          if (data[name] != null) {
            const child = nodeFromJSON(data[name] as JSONNode);
            node[name] = child;
            children.push(child);
          } else {
            node[name] = undefined;
          }
          break;
        }
        case 'l': {
          const arr = data[name] as JSONNode[] | undefined;
          if (arr && arr.length > 0) {
            const items = arr.map(nodeFromJSON);
            node[name] = items;
            children.push(...items);
          } else {
            node[name] = [];
          }
          break;
        }
        case 'p': {
          node[name] = data[name] ?? propDefault(data.kind, name);
          break;
        }
      }
    }
  }
  // For props-only nodes with serialized children, restore from children array
  if (children.length === 0 && data.children && data.children.length > 0) {
    children.push(...data.children.map(nodeFromJSON));
  }
  node.children = children;
  return node as KSNode;
}

