function propDefault(kind: string, name: string): unknown {
  return PD[kind]?.[name] ?? '';
}

/** JSON-safe KSTree representation. */
export interface JSONTree {
  root: JSONNode;
}

/** Serialize a KSTree (root with compilationUnits) to JSON. */
export function treeToJSON(tree: { root: KSNode }): JSONTree {
  return { root: nodeToJSON(tree.root) };
}

/** Deserialize a JSON tree back to a KSTree with typed fields. */
export function treeFromJSON(data: JSONTree): { root: KSNode } {
  const root = nodeFromJSON(data.root);
  // Reconstruct compilationUnits for Program nodes
  if (root.kind === 'Program') {
    (root as any).compilationUnits = root.children;
  }
  return { root };
}
